score.parseScript:
(function () {
    if (window._isPdfParsing) return;
    var embed = document.querySelector("#pdf embed");
    if (!embed) return;


    var pdfUrl = embed.src;
    if (!pdfUrl) return;


    // 鎖定狀態
    window._isPdfParsing = true;
    window.isP = true;


    if (window.mobileApp) {
        window.mobileApp.postMessage({
            detail: { type: "STATUS", payload: "載入 PDF 解析引擎..." },
        });
    }


    var script = document.createElement("script");
    script.src =
        "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.min.js";
    document.head.appendChild(script);


    script.onload = function () {
        window.pdfjsLib.GlobalWorkerOptions.workerSrc =
            "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.worker.min.js";


        if (window.mobileApp) {
            window.mobileApp.postMessage({
                detail: { type: "STATUS", payload: "下載 PDF 成績單..." },
            });
        }


        fetch(pdfUrl)
            .then(function (res) {
                return res.arrayBuffer();
            })
            .then(function (buffer) {
                return window.pdfjsLib.getDocument({ data: buffer }).promise;
            })
            .then(function (pdf) {
                if (window.mobileApp)
                    window.mobileApp.postMessage({
                        detail: { type: "STATUS", payload: "正在提取文字..." },
                    });
                var promises = [];
                for (var i = 1; i <= pdf.numPages; i++) {
                    promises.push(
                        pdf.getPage(i).then(function (page) {
                            return page.getTextContent();
                        }),
                    );
                }
                return Promise.all(promises);
            })
            .then(function (pages) {
                var fullText = pages
                    .map(function (page) {
                        return page.items
                            .map(function (item) {
                                return item.str;
                            })
                            .join(" ");
                    })
                    .join("\n");


                var results = [];
                var regex =
                    /(?:^|\s)([^\s]{1,40})\s+(必修|選修|通識|博雅)\s+(\d+\.\d+)\s+([0-9]{1,3}|通過|不及格|抵免|退選|免修)/g;
                var match;


                while ((match = regex.exec(fullText)) !== null) {
                    var subject = match[1].trim().replace(/\[.*?\]/g, "");
                    if (
                        subject.indexOf("課程") !== -1 ||
                        subject.indexOf("名稱修別") !== -1
                    )
                        continue;


                    var type = match[2];
                    var credit = match[3];
                    var scoreStr = match[4];
                    var isPass = true;
                    var statusText = "及格";
                    var scoreNum = parseInt(scoreStr);


                    if (!isNaN(scoreNum)) {
                        if (scoreNum < 60) {
                            isPass = false;
                            statusText = "不及格";
                        }
                    } else {
                        if (
                            scoreStr === "通過" ||
                            scoreStr === "抵免" ||
                            scoreStr === "免修"
                        ) {
                            isPass = true;
                            statusText = scoreStr;
                        } else {
                            isPass = false;
                            statusText = scoreStr;
                        }
                    }


                    results.push({
                        // 這裡交給 Score.vue 動態替換學期
                        term: "{{TARGET_TERM}}",
                        subject: subject,
                        score: scoreStr,
                        credit: credit,
                        type: type,
                        className: "",
                        isPass: isPass,
                        status: statusText,
                    });
                }


                if (window.mobileApp) {
                    window.mobileApp.postMessage({
                        detail: { type: "DATA_SUCCESS", payload: results },
                    });
                }
            })
            .catch(function (err) {
                window._isPdfParsing = false;
                window.isP = false;
                if (window.mobileApp) {
                    window.mobileApp.postMessage({
                        detail: { type: "ERROR", message: "PDF解析失敗: " + err.message },
                    });
                }
            });
    };
})();

news.webviewScript:
(function() {
  if (window._hasParsedNews) return;

  var items = document.querySelectorAll('#pageptlist .d-item');
  if (items.length === 0) return;

  window._hasParsedNews = true;
  var result = [];

  for (var i = 0; i < items.length; i++) {
    var a = items[i].querySelector('.mtitle a');
    var dateEl = items[i].querySelector('.mdate');
    if (a) {
      result.push({
        title: a.textContent.trim(),
        date: dateEl ? dateEl.textContent.trim() : '',
        link: a.href,
        department: '校園公告'
      });
    }
  }

  if (window.mobileApp) {
    window.mobileApp.postMessage({
      detail: {
        type: 'NEWS_SUCCESS',
        payload: result
      }
    });
  }
})();

mail.webviewScript:
(function() {
  // 防連點鎖：確保 500ms 內只執行一次
  if (window._isHandlingMail) return;
  window._isHandlingMail = true;

  var grid = document.getElementById('ctl00_ContentPlaceHolder1_GridView3');
  var btn = document.getElementById('ctl00_ContentPlaceHolder1_qry_btn1');

  // 1. 若畫面上沒有表格，代表是剛進入，觸發查詢
  if (!grid) {
    if (!sessionStorage.getItem('mail_init_query')) {
      sessionStorage.setItem('mail_init_query', 'true');
      sessionStorage.removeItem('mail_all_data');
      sessionStorage.removeItem('mail_parsed_page');
      sessionStorage.removeItem('mail_done');
      if (btn) btn.click();
    }
    window._isHandlingMail = false;
    return;
  }

  // 2. 若已標記完成，結束執行
  if (sessionStorage.getItem('mail_done') === 'true') {
    window._isHandlingMail = false;
    return;
  }

  // 3. 取得當前頁碼，避免重複抓取相同頁面
  var curPageStr = document.getElementById('ctl00_ContentPlaceHolder1_GridView3_ctl01_lblCurrentPage');
  var curPage = curPageStr ? parseInt(curPageStr.textContent.trim()) : 1;

  var parsedPage = sessionStorage.getItem('mail_parsed_page');
  if (parsedPage && parseInt(parsedPage) === curPage) {
    window._isHandlingMail = false;
    return;
  }

  // 4. 解析當前頁面的資料
  var rows = document.querySelectorAll('.gv-row');
  var pageData = [];
  for (var i = 0; i < rows.length; i++) {
    var tds = rows[i].querySelectorAll('td');
    if (tds.length >= 7) {
      var dateRaw = tds[0].textContent.trim();
      var cls = tds[1].textContent.trim();
      var name = tds[2].textContent.trim();
      var type = tds[5].textContent.trim();
      var location = tds[6].textContent.trim().replace(/\s+/g, ' ');

      // 將西元年轉換為民國年格式 (2026-03-24 -> 1150324)
      var formattedDate = dateRaw;
      var dateParts = dateRaw.split('-');
      if (dateParts.length === 3) {
        var rocYear = parseInt(dateParts[0]) - 1911;
        formattedDate = rocYear.toString() + dateParts[1] + dateParts[2];
      }

      pageData.push({
        name: name,
        department: cls + (type ? ' (' + type + ')' : ''),
        date: formattedDate,
        campus: location
      });
    }
  }

  // 5. 將結果合併至 sessionStorage 總資料陣列
  var allData = JSON.parse(sessionStorage.getItem('mail_all_data') || '[]');
  allData = allData.concat(pageData);
  sessionStorage.setItem('mail_all_data', JSON.stringify(allData));
  sessionStorage.setItem('mail_parsed_page', curPage.toString());

  // 6. 判斷翻頁邏輯 (最多抓 5 頁)
  var nextBtn = document.getElementById('ctl00_ContentPlaceHolder1_GridView3_ctl01_lnkBtnNext');
  var hasNext = nextBtn && !nextBtn.getAttribute('disabled');

  if (curPage < 6 && hasNext) {
     nextBtn.click(); // 觸發 ASP.NET postback 進入下一頁
  } else {
    // 已無下一頁或滿 5 頁，統一發送結果並結束
    sessionStorage.setItem('mail_done', 'true');
    if (window.mobileApp) {
      window.mobileApp.postMessage({ detail: { type: 'MAIL_SUCCESS', payload: allData } });
    }
  }

  window._isHandlingMail = false;
})();
